/**
* Validate and return default LinearGraphQLClient options
*
* @param options initial request options to pass to the graphql client
* @returns parsed graphql client options
*/
function parseClientOptions({ apiKey, accessToken, apiUrl, headers, ...opts }) {
	if (!accessToken && !apiKey) throw new Error("No accessToken or apiKey provided to the LinearClient - create one here: https://linear.app/settings/account/security");
	return {
		headers: {
			Authorization: accessToken ? accessToken.startsWith("Bearer ") ? accessToken : `Bearer ${accessToken}` : apiKey ?? "",
			...headers,
			"User-Agent": serializeUserAgent({ [process.env.npm_package_name ?? "@linear/sdk"]: process.env.npm_package_version ?? "unknown" })
		},
		apiUrl: apiUrl ?? "https://api.linear.app/graphql",
		...opts
	};
}
/**
* Create a Linear API client
*
* @param options request options to pass to the LinearGraphQLClient
*/
var LinearClient = class extends LinearSdk {
	options;
	client;
	constructor(options) {
		const parsedOptions = parseClientOptions(options);
		const graphQLClient = new LinearGraphQLClient(parsedOptions.apiUrl, parsedOptions);
		super((doc, vars) => this.client.request(doc, vars).catch((error) => {
			/** Catch and wrap errors from the LinearGraphQLClient */
			throw parseLinearError(error);
		}));
		this.options = parsedOptions;
		this.client = graphQLClient;
	}
};

